import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const whatsappNumber = "2349122731172";
  const bankInfo = { 
    bank: "PREMIUMTRUST BANK", 
    account: "0112326977", 
    name: "OLUKOYA OMOTOYOSI" 
  };

  // 1. SLIDESHOW DATA (Ensure these filenames exist in public/images/)
  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection.", bgImage: "/images/chops_bg.jpg" },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends.", bgImage: "/images/wigs_bg.jpg" },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining.", bgImage: "/images/lunch_bg.jpg" }
  ];

  // 2. PRODUCT DATA
  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif', WebkitFontSmoothing: 'antialiased' }}>
      
      {/* HEADER BAR */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: 'rgba(0,0,0,0.95)', zIndex: 1000, borderBottom: '1px solid #1a1a1a' }}>
        <img src={Logo} alt="Logo" style={{ height: '55px' }} />
        <div style={{ fontSize: '1.4rem' }}>
          <span style={{ position: 'relative', cursor: 'pointer' }} onClick={() => setIsCartOpen(true)}>🛒
            {cart.length > 0 && <span style={{ position: 'absolute', top: '-8px', right: '-12px', background: terracotta, color: '#fff', borderRadius: '50%', padding: '3px 8px', fontSize: '0.75rem', fontWeight: 'bold' }}>{cart.length}</span>}
          </span>
        </div>
      </header>

      {/* 2. SLIDER SECTION (NEW GALLERY STYLE) */}
      <div style={{ width: '100%', height: '340px', backgroundColor: '#000', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ 
            position: 'absolute', width: '88%', height: '260px', 
            opacity: index === currentSlide ? 1 : 0, 
            transform: index === currentSlide ? 'scale(1)' : 'scale(0.92)',
            transition: 'all 0.9s cubic-bezier(0.4, 0, 0.2, 1)', 
            borderRadius: '24px', overflow: 'hidden', boxShadow: '0 20px 40px rgba(0,0,0,0.7)', border: '1px solid #222'
          }}>
            <img 
              src={process.env.PUBLIC_URL + slide.bgImage} 
              alt={slide.title}
              style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
            />
            <div style={{ position: 'absolute', bottom: 0, left: 0, width: '100%', padding: '25px', background: 'linear-gradient(to top, rgba(0,0,0,0.95), transparent)' }}>
              <h2 style={{ fontSize: '1.8rem', fontWeight: '900', margin: 0, letterSpacing: '1px' }}>{slide.title}</h2>
              <p style={{ fontSize: '1rem', color: gold, margin: '5px 0 0', fontWeight: '700' }}>{slide.subtitle}</p>
            </div>
          </div>
        ))}
      </div>

      {/* 3. NAVIGATION */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '15px 25px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '12px 22px', borderRadius: '30px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#111', color: activeCategory === item ? '#fff' : '#666', fontWeight: '800', transition: '0.3s' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 4. CONTENT AREA */}
      <main style={{ paddingBottom: '140px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '20px', margin: '0 25px 15px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
            <div style={{ width: '100px', height: '100px', borderRadius: '15px', overflow: 'hidden', flexShrink: 0 }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt={item.name} />
            </div>
            <div style={{ flex: 1, paddingLeft: '15px' }}>
              <h4 style={{ fontSize: '1.05rem', margin: 0, fontWeight: '700' }}>{item.name}</h4>
              <p style={{ fontSize: '0.85rem', color: '#777', margin: '4px 0' }}>{item.desc}</p>
              <div style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
            </div>
            {item.isCustom ? (
              <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Booking ${item.name}`)} style={{ backgroundColor: gold, padding: '10px 18px', borderRadius: '20px', border: 'none', fontWeight: '900', fontSize: '0.8rem', cursor: 'pointer' }}>BOOK</button>
            ) : (
              <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '0.8rem', cursor: 'pointer' }}>ADD</button>
            )}
          </div>
        ))}

        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 25px' }}>
            <div style={{ backgroundColor: '#111', padding: '30px', borderRadius: '20px', textAlign: 'center', marginBottom: '20px', border: `1px solid ${isClockedIn ? '#2ecc71' : terracotta}` }}>
              <h4 style={{ color: gold, marginBottom: '15px' }}>{isClockedIn ? "Logged In! ✅" : "Daily Fuel 🍲"}</h4>
              <button onClick={() => setIsClockedIn(true)} style={{ backgroundColor: isClockedIn ? '#2ecc71' : terracotta, color: '#fff', border: 'none', padding: '14px 30px', borderRadius: '15px', fontWeight: '900' }}>{isClockedIn ? "CLOCKED IN" : "START ORDER"}</button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '15px 0', borderBottom: '1px solid #1a1a1a', display: 'flex', justifyContent: 'space-between', fontSize: '0.95rem' }}>
                <span style={{ color: terracotta, fontWeight: '800' }}>{item.day}</span>
                <span style={{ textAlign: 'right', flex: 1, marginLeft: '20px', color: '#ccc' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 25px', marginBottom: '25px' }}>
            <h3 style={{ fontSize: '0.85rem', color: terracotta, textTransform: 'uppercase', marginBottom: '15px', letterSpacing: '1px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '20px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a', marginBottom: '12px' }}>
                <div style={{ width: '90px', height: '90px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0 }}>
                  <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt={item.name} />
                </div>
                <div style={{ flex: 1, paddingLeft: '15px' }}>
                  <h4 style={{ fontSize: '1rem', fontWeight: '700' }}>{item.name}</h4>
                  <div style={{ color: gold, fontWeight: 'bold', marginTop: '4px' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '0.8rem' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 5. CART SUMMARY */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '90%', maxWidth: '450px', backgroundColor: terracotta, padding: '18px 25px', borderRadius: '25px', display: 'flex', justifyContent: 'space-between', zIndex: 1001, boxShadow: '0 10px 30px rgba(0,0,0,0.6)', cursor: 'pointer' }}>
          <span style={{ fontWeight: '900' }}>{cart.length} ITEMS</span>
          <span style={{ fontWeight: '900' }}>VIEW BOX ₦{total.toLocaleString()}</span>
        </div>
      )}

      {/* 6. CART MODAL */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.97)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#000', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '35px 25px', borderTop: '1px solid #222' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ color: gold }}>{showBankDetails ? "Checkout" : "Your Selection"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '1.8rem' }}>✕</button>
            </div>
            {!showBankDetails ? (
              <>
                <div style={{ maxHeight: '35vh', overflowY: 'auto', paddingRight: '5px' }}>
                  {cart.map((item, i) => (
                    <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 0', borderBottom: '1px solid #111' }}>
                      <span style={{ fontSize: '1rem' }}>{item.name}</span>
                      <span style={{ color: gold, fontWeight: '700' }}>₦{item.price}</span>
                    </div>
                  ))}
                </div>
                <div style={{ marginTop: '30px' }}>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '18px', backgroundColor: gold, borderRadius: '15px', border: 'none', fontWeight: '900', marginBottom: '12px' }}>BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Order Details: ${cart.map(c => c.name).join(', ')}. Total: ₦${total.toLocaleString()}`)} style={{ width: '100%', padding: '18px', backgroundColor: '#25D366', borderRadius: '15px', border: 'none', color: '#fff', fontWeight: '900' }}>ORDER ON WHATSAPP</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center', padding: '10px 0' }}>
                <h2 style={{ color: gold, fontSize: '2.4rem', marginBottom: '20px' }}>₦{total.toLocaleString()}</h2>
                <div style={{ backgroundColor: '#0A0A0A', padding: '25px', borderRadius: '20px', textAlign: 'left', border: '1px solid #222' }}>
                  <p style={{ margin: '5px 0' }}><strong>Bank:</strong> {bankInfo.bank}</p>
                  <p style={{ margin: '5px 0' }}><strong>Account:</strong> {bankInfo.account}</p>
                  <p style={{ margin: '5px 0' }}><strong>Name:</strong> {bankInfo.name}</p>
                </div>
                <button onClick={() => setShowBankDetails(false)} style={{ marginTop: '20px', background: 'none', border: 'none', color: '#555', textDecoration: 'underline' }}>Go back</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
